    ssh.execCommand\(''cat /proc/uptime''\),
    ssh.execCommand\(''df -BG / | tail -1''\),
  ]\);
  console.log\(''Docker stats:'', stats.stdout\);
  console.log\(''Uptime:'', uptime.stdout\);
  console.log\(''Disk:'', disk.stdout\);
  ssh.dispose\(\);
}
test\(\).catch\(e => console.log\(''ERROR:'', e.message\)\);
")

